// Helper to get all questions as flat array with subject info
export const getAllQuestions = () => {
  const allQuestions: (BacQuestion & { subject: string })[] = [];
  
  const subjectMap: Record<string, string> = {
    matematica: "Matematică",
    romana: "Română",
    istorie: "Istorie",
    biologie: "Biologie",
    fizica: "Fizică",
    chimie: "Chimie",
    informatica: "Informatică",
  };
  
  for (const [key, questions] of Object.entries(bacQuestions)) {
    for (const q of questions) {
      allQuestions.push({ ...q, subject: subjectMap[key] || key });
    }
  }
  
  return allQuestions;
};

// Helper to convert A/B/C/D correct answer to index (0-3)
export const correctToIndex = (correct: "A" | "B" | "C" | "D"): number => {
  return { A: 0, B: 1, C: 2, D: 3 }[correct];
};
